import { IMessageComposer } from '@nitrots/nitro-renderer';

export class UpdateInventoryItemComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(inventoryId: number, newSlot: number) {
        this._data = [inventoryId, newSlot];
    }

    public getMessageArray(): any[] {
        //console.log("Packet UpdateInventorySlotComposer sent");
        return this._data;
    }

    public dispose(): void {
        return;
    }
}